const order = $input.item.json;
const customer = order.customer || {};

return {
  json: {
    orderId: order.id,
    orderNumber: order.order_number,
    orderTotal: parseFloat(order.total_price || 0),
    orderCurrency: order.currency || 'USD',
    orderStatus: order.financial_status || 'unknown',
    customerId: customer.id,
    customerEmail: customer.email || '',
    customerFirstName: customer.first_name || 'Customer',
    customerLastName: customer.last_name || '',
    customerPhone: customer.phone || '',
    totalOrderCount: customer.orders_count || 1,
    totalSpend: parseFloat(customer.total_spent || 0),
    customerTags: customer.tags || '',
    customerCreatedAt: customer.created_at || '',
    lineItems: (order.line_items || []).map(i => ({ name: i.name, qty: i.quantity, price: parseFloat(i.price) })),
    orderCreatedAt: order.created_at || new Date().toISOString()
  }
};

const orders = $input.item.json.orders || [];
const current = $('Extract Order & Customer').item.json;
const today = new Date();

// Core metrics
const paidOrders = orders.filter(o => o.financial_status === 'paid');
const totalOrders = paidOrders.length;
const totalRevenue = paidOrders.reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);
const aov = totalOrders > 0 ? totalRevenue / totalOrders : 0;

// Recency — days since last purchase
const sortedOrders = paidOrders.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
const lastOrderDate = sortedOrders[0] ? new Date(sortedOrders[0].created_at) : null;
const daysSinceLastOrder = lastOrderDate ? Math.floor((today - lastOrderDate) / (1000 * 60 * 60 * 24)) : 9999;

// Frequency — avg days between orders
let avgDaysBetweenOrders = 0;
if (sortedOrders.length > 1) {
  const intervals = [];
  for (let i = 0; i < sortedOrders.length - 1; i++) {
    const diff = Math.abs(new Date(sortedOrders[i].created_at) - new Date(sortedOrders[i+1].created_at)) / (1000 * 60 * 60 * 24);
    intervals.push(diff);
  }
  avgDaysBetweenOrders = intervals.reduce((a, b) => a + b, 0) / intervals.length;
}

// Predicted LTV (simple 12-month projection)
const purchaseFrequencyPerYear = avgDaysBetweenOrders > 0 ? 365 / avgDaysBetweenOrders : 1;
const predictedAnnualLTV = aov * purchaseFrequencyPerYear;

// RFM Churn Prediction
let churnRisk, segment;
if (totalOrders >= 5 && daysSinceLastOrder <= 30 && aov >= 100) {
  segment = 'Champion'; churnRisk = 'LOW';
} else if (totalOrders >= 3 && daysSinceLastOrder <= 60) {
  segment = 'Loyal'; churnRisk = 'LOW';
} else if (totalOrders >= 2 && daysSinceLastOrder <= 90) {
  segment = 'At-Risk'; churnRisk = 'MEDIUM';
} else if (totalOrders >= 2 && daysSinceLastOrder > 90) {
  segment = 'Lost'; churnRisk = 'HIGH';
} else if (totalOrders === 1 && daysSinceLastOrder > 60) {
  segment = 'One-Time Buyer'; churnRisk = 'HIGH';
} else {
  segment = 'New Customer'; churnRisk = 'LOW';
}

const isVIP = totalRevenue >= 1000 || aov >= 250;
const productHistory = paidOrders.flatMap(o => (o.line_items || []).map(i => i.name)).slice(0, 10);

return {
  json: {
    ...current,
    totalOrders,
    totalRevenue: Math.round(totalRevenue * 100) / 100,
    aov: Math.round(aov * 100) / 100,
    daysSinceLastOrder,
    avgDaysBetweenOrders: Math.round(avgDaysBetweenOrders),
    predictedAnnualLTV: Math.round(predictedAnnualLTV * 100) / 100,
    purchaseFrequencyPerYear: Math.round(purchaseFrequencyPerYear * 10) / 10,
    churnRisk,
    segment,
    isVIP,
    productHistory,
    metricsGeneratedAt: new Date().toISOString()
  }
};

const raw = $input.item.json.content?.[0]?.text || '{}';
const customer = $('Calculate Customer Metrics').item.json;
let retention;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  retention = match ? JSON.parse(match[0]) : {};
} catch(e) {
  retention = { emailSubject: 'We miss you!', emailBody: '<p>Hi ' + customer.customerFirstName + ', we would love to see you back.</p>', discountCode: null, discountPercent: 0, smsMessage: 'Hi! We miss you. Come back for 10% off.', recommendedProducts: [] };
}
return {
  json: {
    ...customer,
    retentionEmailSubject: retention.emailSubject,
    retentionEmailBody: retention.emailBody,
    discountCode: retention.discountCode,
    discountPercent: retention.discountPercent || 0,
    retentionSms: retention.smsMessage,
    recommendedProducts: retention.recommendedProducts || []
  }
};

